INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('94774826-0c1e-5d79-b8df-c6335d6088c4', 'arabic-3eme', 'أبني الجملة: اسميّةٌ أم فعليّة؟', 'أميّز بين الجملة الاسميّة التي تبدأ باسمٍ (مبتدأ + خبر) والجملة الفعليّة التي تبدأ بفعلٍ (فعل + فاعل)، وأعرف كيف أحكم على الجملة من كلمتها الأولى', '# ⚔️ أبني الجملة: اسميّةٌ أم فعليّة؟ — سرُّ الكلمة الأولى

> 💡 «انظر إلى أوّل كلمةٍ في الجملة، تعرفْ نوعها كلَّه؛ فالبدايةُ مفتاحُ السرّ.»

أنت الآن بنّاءُ جُمَلٍ بطل. كلُّ جملةٍ في لغتنا نوعان: **جملةٌ اسميّة** أو **جملةٌ فعليّة**. كيف نفرّق بينهما؟ بكلمةٍ واحدةٍ فقط: **الكلمة الأولى**. هيّا نتعلّم السرّ.

## 🏰 ما الجملة الاسميّة؟

**الجملة الاسميّة** هي جملةٌ تبدأ بـ**اسمٍ**. الاسمُ كلمةٌ تدلّ على إنسانٍ أو حيوانٍ أو شيءٍ أو مكان، مثل: *العصفور، البحر، التلميذ، الوردة*.

*مثال: «العصفورُ جميلٌ.» بدأت بـ«العصفور» وهو اسم، فهي جملةٌ اسميّة.*

تتكوّن الجملة الاسميّة من جزأين: **المبتدأ** و**الخبر**.

## ⚡ ما الجملة الفعليّة؟

**الجملة الفعليّة** هي جملةٌ تبدأ بـ**فعلٍ**. الفعلُ كلمةٌ تدلّ على عملٍ يحدث، مثل: *طار، يكتبُ، لعبَ، تأكلُ*.

*مثال: «طارَ العصفورُ.» بدأت بـ«طار» وهو فعل، فهي جملةٌ فعليّة.*

تتكوّن الجملة الفعليّة من جزأين: **الفعل** و**الفاعل**.

## 🔮 المبتدأ والخبر (في الجملة الاسميّة)

- **المبتدأ**: الاسمُ الذي نبدأ به ونتحدّث عنه (مرفوع).
- **الخبر**: ما نخبر به عن المبتدأ، يُكمل المعنى (مرفوع).

*مثال: «الجوُّ صافٍ.» المبتدأ: الجوُّ. الخبر: صافٍ.*
*مثال: «المعلّمةُ نشيطةٌ.» المبتدأ: المعلّمةُ. الخبر: نشيطةٌ.*

## 🛡️ الفعل والفاعل (في الجملة الفعليّة)

- **الفعل**: الكلمة الأولى التي تدلّ على العمل.
- **الفاعل**: الاسمُ الذي قام بالعمل (مرفوع).

*مثال: «شربَ الطفلُ الحليبَ.» الفعل: شربَ. الفاعل: الطفلُ (هو من شرب).*
*مثال: «تطيرُ الفراشةُ.» الفعل: تطيرُ. الفاعل: الفراشةُ.*

> 🗡️ السرّ الذهبيّ: **اقرأ الكلمة الأولى فقط**. إن كانت اسمًا فالجملة اسميّة، وإن كانت فعلًا فالجملة فعليّة. لا حاجة لقراءة الجملة كلّها لتعرف نوعها.

## 🧮 كيف أميّز بينهما؟ جدولُ السرّ

| النوع | تبدأ بـ | أجزاؤها | مثال |
| --- | --- | --- | --- |
| **اسميّة** | اسم | مبتدأ + خبر | *القمرُ منيرٌ* |
| **فعليّة** | فعل | فعل + فاعل | *أكلَ القطُّ* |

اسأل نفسك دائمًا: *«هل الكلمة الأولى عملٌ يحدث (فعل) أم اسمُ شيءٍ (اسم)؟»*

> ⚠️ الفخّ الشائع: الجملةُ نفسها قد نقلبها! «العصفورُ طارَ» اسميّة (بدأت باسم)، لكنّ «طارَ العصفورُ» فعليّة (بدأت بفعل). **العبرة بمن يأتي أوّلًا**، لا بالكلمات نفسها.

> 🏆 أحسنت أيّها البنّاء البطل! صرتَ تعرف الجملة الاسميّة (مبتدأ + خبر) والفعليّة (فعل + فاعل)، وتميّز بينهما من الكلمة الأولى. ابنِ الآن جُملك بثقة!', '# 📜 ملخّص: أبني الجملة: اسميّةٌ أم فعليّة؟

- **الجملة الاسميّة**: تبدأ باسمٍ (إنسان أو حيوان أو شيء)، مثل «العصفورُ جميلٌ».
- **الجملة الفعليّة**: تبدأ بفعلٍ (عملٍ يحدث)، مثل «طارَ العصفورُ».
- **المبتدأ والخبر**: جزآ الجملة الاسميّة؛ المبتدأ نبدأ به والخبر يُخبر عنه (كلاهما مرفوع).
- **الفعل والفاعل**: جزآ الجملة الفعليّة؛ الفعل عملٌ والفاعل من قام به (مرفوع).
- **سرّ التمييز**: انظر إلى الكلمة الأولى فقط؛ اسمٌ ← اسميّة، فعلٌ ← فعليّة.
- **الفخّ**: العبرة بأوّل كلمةٍ؛ «العصفورُ طارَ» اسميّة، و«طارَ العصفورُ» فعليّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('80c7b0f3-24b7-51ce-9eb5-0a33f12058e6', 'arabic-3eme', 'المفرد والمثنّى والجمع: واحدٌ، اثنان، كثيرون', 'أميّز المفرد (واحد) والمثنّى (اثنان) والجمع (أكثر من اثنين)، وأكوّن المثنّى بزيادة (ان/ين)، وأعرف جمع المذكّر السالم (ون/ين) وجمع المؤنّث السالم (ات) وأمثلةً محفوظةً من جمع التكسير', '# ⚔️ المفرد والمثنّى والجمع — واحدٌ، اثنان، كثيرون

> 💡 «عُدَّ الأشياء تعرفْ كلمتها: واحدٌ مفرد، اثنان مثنّى، وما زاد فجمع.»

أنت الآن عدّادُ الكلمات البطل. كلُّ اسمٍ في لغتنا له ثلاثُ حالاتٍ حسب العدد: **مفرد** (واحد)، و**مثنّى** (اثنان)، و**جمع** (كثيرون). كيف نعرف كلَّ حالةٍ ونكوّنها؟ هيّا نتعلّم.

## 🏰 ما المفرد؟

**المفرد** هو ما دلّ على **واحدٍ** فقط: شخصٌ واحد، أو حيوانٌ واحد، أو شيءٌ واحد.

*أمثلة: كتابٌ، تلميذٌ، وردةٌ، قلمٌ، معلّمةٌ.*

كلُّ هذه كلماتٌ تدلّ على شيءٍ واحدٍ، فهي مفرد.

## ⚡ ما المثنّى؟ (اثنان)

**المثنّى** هو ما دلّ على **اثنين**. نكوّنه من المفرد بزيادةٍ في آخره:

- نزيد **«ان»**: كتابٌ ← *كتابان*، تلميذٌ ← *تلميذان*.
- أو نزيد **«ين»**: كتابٌ ← *كتابَيْن*، تلميذٌ ← *تلميذَيْن*.

*مثال: «جاء تلميذان» (اثنان)، «رأيتُ تلميذَيْن» (اثنان كذلك).*

> 🗡️ السرّ: لتكوّن المثنّى، خذ المفرد وأضف **ان** أو **ين** في آخره فقط. لا تغيّر باقي الحروف.

## 🔮 ما الجمع؟ (أكثر من اثنين)

**الجمع** هو ما دلّ على **أكثر من اثنين** (ثلاثةٌ فأكثر).

*أمثلة: كُتُبٌ، تلاميذُ، معلّمونَ، معلّماتٌ، وُرودٌ.*

الجمع أنواع، نتعلّم منها ثلاثة:

## 🛡️ أنواع الجمع الثلاثة

**1) جمع المذكّر السالم**: نزيد **«ون»** أو **«ين»** على المفرد المذكّر العاقل، وتبقى حروف المفرد كما هي.
*مثال: معلّمٌ ← معلّمونَ / معلّمين، مسلمٌ ← مسلمونَ.*

**2) جمع المؤنّث السالم**: نزيد **«ات»** على المفرد المؤنّث، وتبقى حروفه كما هي.
*مثال: معلّمةٌ ← معلّماتٌ، وردةٌ ← وَرداتٌ، طالبةٌ ← طالباتٌ.*

**3) جمع التكسير**: يتغيّر شكل الكلمة (تتكسّر)، فنحفظه كما هو.
*مثال: كتابٌ ← كُتُبٌ، ولدٌ ← أولادٌ، بيتٌ ← بيوتٌ، قلمٌ ← أقلامٌ.*

## 🧮 جدولُ العدد الكامل

| الكلمة | مفرد (1) | مثنّى (2) | جمع (3+) |
| --- | --- | --- | --- |
| **معلّم** | معلّمٌ | معلّمان | معلّمونَ |
| **معلّمة** | معلّمةٌ | معلّمتان | معلّماتٌ |
| **كتاب** | كتابٌ | كتابان | كُتُبٌ |

> ⚠️ الفخّ الشائع: لا تخلط بين **المثنّى** (اثنان فقط) و**الجمع** (ثلاثةٌ فأكثر). «معلّمان» مثنّى (اثنان)، أمّا «معلّمونَ» فجمع (كثيرون). وتذكّر: جمع التكسير يُحفَظ ولا يُبنى بقاعدة.

> 🏆 أحسنت أيّها العدّاد البطل! صرتَ تعرف المفرد والمثنّى والجمع، وتكوّن المثنّى بـ(ان/ين)، وتميّز جمع المذكّر (ون/ين) وجمع المؤنّث (ات) وجمع التكسير المحفوظ. عُدَّ الآن واكتب بثقة!', '# 📜 ملخّص: المفرد والمثنّى والجمع

- **المفرد**: ما دلّ على واحدٍ فقط، مثل: كتابٌ، تلميذٌ، وردةٌ.
- **المثنّى**: ما دلّ على اثنين؛ نكوّنه بزيادة «ان» أو «ين» على المفرد، مثل: كتابان / كتابَيْن.
- **الجمع**: ما دلّ على أكثر من اثنين (ثلاثةٌ فأكثر).
- **جمع المذكّر السالم**: نزيد «ون» أو «ين»، مثل: معلّمٌ ← معلّمونَ / معلّمين.
- **جمع المؤنّث السالم**: نزيد «ات»، مثل: معلّمةٌ ← معلّماتٌ.
- **جمع التكسير**: يتغيّر شكل الكلمة فنحفظه، مثل: كتابٌ ← كُتُبٌ، ولدٌ ← أولادٌ.
- **الفخّ**: المثنّى اثنان فقط، والجمع ثلاثةٌ فأكثر؛ وجمع التكسير محفوظٌ لا يُبنى بقاعدة.', 3)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('523d1d7b-bb04-5d44-939c-5426f74a3373', 'arabic-3eme', 'سرُّ التاء: مذكّرٌ أم مؤنّث؟', 'أميّز بين الاسم المذكّر (ولدٌ، قلمٌ) والاسم المؤنّث (بنتٌ، وردةٌ)، وأعرف أنّ علامة التأنيث الأشهر هي التاء المربوطة (ة)، وأتعرّف على المؤنّث بلا تاء (شمس، يد، أمّ)، وأحوّل المذكّر إلى مؤنّث بزيادة التاء', '# ⚔️ سرُّ التاء: مذكّرٌ أم مؤنّث؟ — كنزُ علامة التأنيث

> 💡 «كلُّ اسمٍ في لغتنا إمّا فارسٌ مذكّرٌ وإمّا فارسةٌ مؤنّثة؛ ومن عرف العلامة عرف القبيلة.»

أنت الآن لغويٌّ بطل. كلُّ اسمٍ في العربية نوعان: **مذكّر** أو **مؤنّث**. المذكّر للذكور (الأولاد والرجال)، والمؤنّث للإناث (البنات والنساء). لكنّ الأشياء أيضًا لها نوع! هيّا نكتشف العلامة السحريّة التي تكشف لنا النوع.

## 🏰 ما الاسم المذكّر؟

**الاسم المذكّر** يدلّ على ذكرٍ من الناس أو الحيوان، أو على شيءٍ نعامله معاملة الذكر.

نقول عنه: *هذا*. مثل: *هذا ولدٌ، هذا معلّمٌ، هذا قلمٌ، هذا بابٌ، هذا أسدٌ*.

أغلب الأسماء المذكّرة **تنتهي بحرفٍ ساكنٍ بلا تاء** في آخرها.

## 🔮 ما الاسم المؤنّث؟

**الاسم المؤنّث** يدلّ على أنثى من الناس أو الحيوان، أو على شيءٍ نعامله معاملة الأنثى.

نقول عنه: *هذه*. مثل: *هذه بنتٌ، هذه معلّمةٌ، هذه وردةٌ، هذه شجرةٌ، هذه قطّةٌ*.

> 🗡️ السرّ: جرّب كلمة **«هذا»** للمذكّر و**«هذه»** للمؤنّث. إن صحّت «هذه» فالاسم مؤنّث!

## 🛡️ علامة التأنيث الكبرى: التاء المربوطة (ة)

أشهر علامةٍ تدلّ على المؤنّث هي **التاء المربوطة (ة)** في آخر الكلمة.

إذا رأيت اسمًا ينتهي بـ **ة**، فهو غالبًا **مؤنّث**: *معلّمة، وردة، تلميذة، سيّارة، حديقة، تفّاحة*.

| النوع | العلامة | أمثلة |
| --- | --- | --- |
| **مذكّر** | بلا تاءٍ مربوطة | *ولد، معلّم، قلم، أسد* |
| **مؤنّث** | بالتاء المربوطة (ة) | *بنت، معلّمة، وردة، قطّة* |

## ⚡ أحوّل المذكّر إلى مؤنّث

لنحوّل اسمًا مذكّرًا إلى مؤنّثٍ، **نزيد التاء المربوطة (ة)** في آخره.

- *معلّم* ← **معلّمة**
- *تلميذ* ← **تلميذة**
- *لاعب* ← **لاعبة**
- *كبير* ← **كبيرة**

*مثال في جملة: «المعلّمُ شرحَ الدرس» تصير «المعلّمةُ شرحَتِ الدرس».*

## 🧮 مؤنّثٌ بلا تاء (المؤنّث المعنويّ)

انتبه أيّها البطل! بعضُ الأسماء **مؤنّثةٌ ولكن بلا تاءٍ مربوطة**. نحفظها كما هي:

*شمس، أرض، يد، عين، أمّ، نار، سماء، ريح*.

نعرف أنّها مؤنّثة لأنّنا نقول: *هذه شمسٌ، هذه يدٌ، هذه أمٌّ*. وهي قليلةٌ، نحفظها بالتدريب.

> ⚠️ الفخّ الشائع: لا تظنَّ أنّ كلَّ اسمٍ بلا تاءٍ مذكّر! كلمات مثل *شمس، يد، أمّ* مؤنّثةٌ رغم أنّها بلا تاء. جرّب «هذه» لتتأكّد.

> 🏆 أحسنت أيّها اللغويُّ البطل! صرتَ تميّز المذكّر من المؤنّث، وتعرف علامة التاء المربوطة، وتحوّل المذكّر إلى مؤنّث، وتحفظ المؤنّث الذي بلا تاء. اِفتح الآن أبواب الكلمات وصنّفها بثقة!', '# 📜 ملخّص: سرُّ التاء: مذكّرٌ أم مؤنّث؟

- **الاسم المذكّر**: يدلّ على ذكرٍ أو شيءٍ نقول له «هذا»؛ مثل ولد، معلّم، قلم.
- **الاسم المؤنّث**: يدلّ على أنثى أو شيءٍ نقول له «هذه»؛ مثل بنت، معلّمة، وردة.
- **علامة التأنيث الكبرى**: التاء المربوطة (ة) في آخر الكلمة؛ مثل معلّمة، شجرة، سيّارة.
- **التحويل إلى مؤنّث**: نزيد التاء المربوطة (ة)؛ معلّم ← معلّمة، تلميذ ← تلميذة.
- **مؤنّثٌ بلا تاء**: كلماتٌ مؤنّثةٌ نحفظها رغم أنّها بلا تاء؛ شمس، أرض، يد، عين، أمّ، نار، سماء.
- **الحيلة**: جرّب «هذا» للمذكّر و«هذه» للمؤنّث لتعرف النوع.
- **الفخّ**: ليس كلُّ اسمٍ بلا تاءٍ مذكّرًا؛ شمس ويد وأمّ مؤنّثةٌ بلا تاء.', 4)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('cb6f109a-1e08-5f0f-94b0-ebea80d41e4c', 'arabic-3eme', 'رحلةُ الفعل عبر الزمن: أمسِ واليومَ والأمر', 'أميّز أزمنة الفعل الثلاثة: الماضي (حدثٌ انتهى مثل كتبَ)، والمضارع (يحدث الآن أو غدًا مثل يكتبُ)، وفعل الأمر (طلبٌ مثل اُكتبْ)، وأستعين بالكلمات الدالّة (أمسِ، الآن، غدًا)، وأحوّل الفعل من زمنٍ إلى آخر', '# ⚔️ رحلةُ الفعل عبر الزمن — أمسِ واليومَ والأمر

> 💡 «الفعلُ مركبةٌ تسافر في الزمن: مرّةً إلى الأمس، ومرّةً تعيش اليوم، ومرّةً تأمرُ بالغد.»

أنت الآن مسافرٌ بطل في الزمن. **الفعل** كلمةٌ تدلّ على عملٍ (كتبَ، لعبَ، أكلَ). ولكلِّ فعلٍ **زمنٌ**: هل وقع العملُ أمسِ؟ أم يقع الآن؟ أم نطلبه طلبًا؟ هيّا نتعلّم أزمنة الفعل الثلاثة.

## 🏰 الفعل الماضي: حدثٌ وانتهى

**الفعل الماضي** يدلّ على عملٍ **وقع وانتهى** قبل الآن، في الزمن الماضي.

أمثلة: *كتبَ، لعبَ، أكلَ، ذهبَ، شربَ*. غالبًا يكون آخره مفتوحًا.

*مثال: «كتبَ الولدُ الدرسَ أمسِ.» العمل (الكتابة) انتهى.*

> 🗡️ السرّ: كلمة **«أمسِ»** صديقةُ الماضي. إذا صلحت «أمسِ» مع الفعل فهو ماضٍ: *لعبَ أمسِ*.

## ⚡ الفعل المضارع: يحدث الآن أو غدًا

**الفعل المضارع** يدلّ على عملٍ **يحدث الآن** أو **سيحدث غدًا** (لم ينتهِ بعد).

يبدأ غالبًا بحرفٍ زائدٍ من حروف **(أ، ن، ي، ت)**: *يكتبُ، تلعبُ، نأكلُ، أشربُ*.

*مثال: «يكتبُ الولدُ الدرسَ الآن.» العمل ما زال يحدث.*

> 🗡️ السرّ: كلمتا **«الآن»** و**«غدًا»** صديقتا المضارع: *يلعبُ الآن، يسافرُ غدًا*.

## 🛡️ فعل الأمر: طلبٌ وأمر

**فعل الأمر** يدلّ على **طلبٍ** نطلب به من شخصٍ أن يفعل شيئًا الآن.

أمثلة: *اُكتبْ، اِلعبْ، اِشربْ، اُدرسْ، اِجلسْ*. نقوله لمن نخاطبه: *اُكتبْ يا وليد!*

*مثال: «اِلعبْ مع أصحابك!» هذا طلبٌ بأن يلعب.*

## 🔮 جدولُ الأزمنة الثلاثة

| الزمن | متى؟ | الكلمة الدالّة | مثال |
| --- | --- | --- | --- |
| **الماضي** | حدثٌ انتهى | أمسِ | *كتبَ، لعبَ* |
| **المضارع** | الآن أو غدًا | الآن، غدًا | *يكتبُ، يلعبُ* |
| **الأمر** | طلبٌ | (لا زمن، طلب) | *اُكتبْ، اِلعبْ* |

## 🧮 أحوّل الفعل من زمنٍ إلى آخر

الفعل الواحد نستطيع تحويله بين الأزمنة الثلاثة:

- *كتبَ* (ماضٍ) ← *يكتبُ* (مضارع) ← *اُكتبْ* (أمر)
- *لعبَ* (ماضٍ) ← *يلعبُ* (مضارع) ← *اِلعبْ* (أمر)
- *شربَ* (ماضٍ) ← *يشربُ* (مضارع) ← *اِشربْ* (أمر)

> ⚠️ الفخّ الشائع: لا تخلط بين الماضي والمضارع! انظر إلى **أوّل الفعل**: إن بدأ بـ (ي، ت، ن، أ) فهو مضارعٌ غالبًا (*يكتب*)، وإن لم يبدأ بها وكان عملًا انتهى فهو ماضٍ (*كتبَ*). واستعن بالكلمة الدالّة: أمسِ أم الآن؟

> 🏆 أحسنت أيّها المسافرُ البطل! صرتَ تعرف الفعل الماضي والمضارع والأمر، وتستعين بالكلمات الدالّة، وتحوّل الفعل بين الأزمنة. سافِرْ الآن في الزمن بثقة!', '# 📜 ملخّص: رحلةُ الفعل عبر الزمن

- **الفعل**: كلمةٌ تدلّ على عملٍ (كتبَ، لعبَ، أكلَ)، وله زمنٌ يدلّ على وقت العمل.
- **الفعل الماضي**: عملٌ وقع وانتهى قبل الآن؛ مثل كتبَ، لعبَ، ذهبَ؛ كلمته الدالّة «أمسِ».
- **الفعل المضارع**: عملٌ يحدث الآن أو غدًا، يبدأ بـ (أ، ن، ي، ت)؛ مثل يكتبُ، تلعبُ؛ كلمتاه «الآن» و«غدًا».
- **فعل الأمر**: طلبٌ نطلب به فعل شيءٍ؛ مثل اُكتبْ، اِلعبْ، اِجلسْ.
- **التحويل بين الأزمنة**: كتبَ (ماضٍ) ← يكتبُ (مضارع) ← اُكتبْ (أمر).
- **الحيلة**: انظر إلى أوّل الفعل (ي، ت، ن، أ = مضارع) واستعن بالكلمة الدالّة (أمسِ أم الآن؟).
- **الفخّ**: لا تخلط بين الماضي والمضارع؛ المضارع يبدأ بحرفٍ زائدٍ والماضي عملٌ انتهى.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('19cfd550-980c-5523-b546-238798bd123d', 'arabic-3eme', 'أسرارُ الضمائر المنفصلة', 'أتعرّف على الضمائر المنفصلة: ضمائر المتكلّم (أنا، نحن)، وضمائر المخاطب (أنتَ، أنتِ)، وضمائر الغائب (هو، هي، هم)، وأستعملها بدل الاسم، وأطابق بين الضمير والمذكّر والمؤنّث', '# ⚔️ أسرارُ الضمائر المنفصلة — كلماتٌ سحريّةٌ تنوبُ عن الأسماء

> 💡 «بدل أن تُعيدَ الاسمَ مرّةً بعد مرّة، استعمل ضميرًا واحدًا فيفهمك الجميع.»

تخيّل أنّك تتحدّث عن صديقك محمّدٍ، فتقول: «محمّدٌ لعب، محمّدٌ أكل، محمّدٌ نام». مُتعِبٌ، أليس كذلك؟ لذلك نستعمل كلماتٍ صغيرةً قويّةً اسمُها **الضمائر** تنوبُ عن الاسم. هيّا نكتشف أسرارها.

## 🏰 ما الضمير؟

**الضميرُ** كلمةٌ تنوبُ عن الاسم حتّى لا نُعيدَه. بدل أن نقول الاسمَ كلَّ مرّة، نقول الضميرَ فيفهمُ السامعُ مَن نقصد.

*مثال: «محمّدٌ ذهب إلى المدرسة» ← «**هو** ذهب إلى المدرسة».* كلمة **هو** ضميرٌ نابت عن «محمّد».

نسمّيها **الضمائر المنفصلة** لأنّها تأتي وحدَها، منفصلةً عن الكلمات الأخرى، في أوّل الجملة غالبًا.

## 🔮 الضمائر الثلاثة: متكلّمٌ ومخاطبٌ وغائب

الضمائر ثلاثةُ أنواعٍ حسب مَن نتحدّث عنه:

| النوع | معناه | الضمائر |
| --- | --- | --- |
| **المتكلّم** | الذي يتكلّم عن نفسه | **أنا** (للواحد)، **نحن** (للجماعة) |
| **المخاطب** | الذي نتحدّث إليه | **أنتَ** (للولد)، **أنتِ** (للبنت) |
| **الغائب** | الذي نتحدّث عنه وهو بعيد | **هو** (للولد)، **هي** (للبنت)، **هم** (للجماعة) |

*مثال: أقول عن نفسي «**أنا** تلميذٌ»، وأقول لصديقي «**أنتَ** تلميذٌ»، وأقول عن غيره «**هو** تلميذٌ».*

## ⚡ أستعملُ الضمير بدل الاسم

لِنحوّلَ اسمًا إلى ضميرٍ، نسأل: *مَن هذا؟ ولدٌ أم بنتٌ؟ واحدٌ أم جماعة؟*

- اسمُ ولدٍ واحدٍ غائب ← **هو** (محمّدٌ نجح ← **هو** نجح).
- اسمُ بنتٍ واحدةٍ غائبة ← **هي** (فاطمةُ نجحت ← **هي** نجحت).
- جماعةٌ غائبة ← **هم** (التلاميذُ نجحوا ← **هم** نجحوا).

> 🗡️ السرّ: انظر إلى الاسم الذي تريد تعويضه، ثمّ ضع الضميرَ المناسبَ مكانه في أوّل الجملة.

## 🛡️ مطابقةُ الضمير: مذكّرٌ أم مؤنّث؟

الضميرُ يجب أن **يُطابقَ** الاسمَ في التذكير والتأنيث:

- **هو** للمذكّر (الولد، الرجل، القطّ).
- **هي** للمؤنّث (البنت، المرأة، القطّة).

*مثال: «سعادُ» بنتٌ، فنقول «**هي**» لا «هو». و«عليٌّ» ولدٌ، فنقول «**هو**» لا «هي».*

والمؤنّثُ كذلك حتّى لو كان غيرَ عاقل: «الشمسُ» نقول عنها «**هي** مشرقةٌ».

## 🧮 أنا ونحن: واحدٌ أم جماعة؟

ضميرُ المتكلّم نوعان حسب العدد:

- **أنا**: حين أتكلّمُ عن نفسي وحدي. *(أنا أحبُّ القراءة.)*
- **نحن**: حين أتكلّمُ عن نفسي ومعي غيري. *(نحن نلعبُ في الساحة.)*

وكذلك المخاطب: **أنتَ** لولدٍ واحد، و**أنتِ** لبنتٍ واحدة. انتبه للحركة في آخر الكلمة: أنتَ بالفتحة للذكر، أنتِ بالكسرة للأنثى.

> ⚠️ الفخّ الشائع: لا تخلط بين **أنتَ** (مخاطب، أمامك) و**هو** (غائب، بعيد). إذا كنتَ تتحدّث **إلى** الشخص فهو مخاطب، وإذا كنتَ تتحدّث **عن** شخصٍ بعيد فهو غائب.

> 🏆 أحسنت أيّها البطل! صرتَ تعرف الضمائرَ الثلاثة، وتستعملها بدل الأسماء، وتطابق بين المذكّر والمؤنّث. تكلّم الآن بلا تكرارٍ مُملٍّ!', '# 📜 ملخّص: أسرارُ الضمائر المنفصلة

- **الضمير**: كلمةٌ تنوبُ عن الاسم حتّى لا نُعيدَه (محمّدٌ ذهب ← هو ذهب).
- **المتكلّم**: الذي يتكلّم عن نفسه ← أنا (للواحد)، نحن (للجماعة).
- **المخاطب**: الذي نتحدّث إليه ← أنتَ (للولد)، أنتِ (للبنت).
- **الغائب**: الذي نتحدّث عنه وهو بعيد ← هو (للولد)، هي (للبنت)، هم (للجماعة).
- **استعمال الضمير**: نضع الضميرَ المناسبَ مكان الاسم في أوّل الجملة.
- **المطابقة**: هو للمذكّر، هي للمؤنّث (سعادُ ← هي، عليٌّ ← هو).
- **أنا / نحن**: أنا لنفسي وحدي، نحن لنفسي ومعي غيري.
- **الفخّ**: لا تخلط بين أنتَ (مخاطب أمامك) وهو (غائب بعيد).', 6)
ON CONFLICT (id) DO UPDATE SET
