INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4baedf3-120b-5b96-a0d0-bbd3646d65f3', '66821642-4fcf-584d-ac34-a52db6a8e912', 'في النصّ نفسه: «فرح سميرٌ كثيرًا.»  ما معنى «فرح»؟', '[{"id":"a","text":"تعبَ ومرضَ"},{"id":"b","text":"غضبَ وبكى"},{"id":"c","text":"سُرَّ وابتسمَ"},{"id":"d","text":"نامَ بسرعةٍ"}]'::jsonb, 'c', 'نفهم المعنى من السياق: سميرٌ غرس شجرةً وسقاها، فهذا عملٌ جميلٌ يجلب السرور. «فرح» معناها سُرَّ وابتسم، عكس حزن.', 5)
