INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7aaec2c9-b471-593f-9476-eb470654eaad', '66821642-4fcf-584d-ac34-a52db6a8e912', 'ما العنوان الأنسب لهذا النصّ؟', '[{"id":"a","text":"سميرٌ المريض"},{"id":"b","text":"سميرٌ يغرس شجرةً"},{"id":"c","text":"رحلةٌ إلى البحر"},{"id":"d","text":"يومٌ في المدرسة"}]'::jsonb, 'b', 'العنوان يلخّص الفكرة العامّة. النصّ كلّه عن غرس سميرٍ شجرةً وسقيها، فالعنوان الأنسب «سميرٌ يغرس شجرةً». الخطأ الشائع اختيار عنوانٍ من تفصيلٍ خارج النصّ.', 6)
