INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e65af214-f28c-585c-89d8-d4d355cfeb67', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'اقرأ: «وجدت ليلى قطّةً صغيرةً في الشارع، فحملتها إلى البيت وأطعمتها.»  ماذا وجدت ليلى؟', '[{"id":"a","text":"كلبًا"},{"id":"b","text":"قطّةً صغيرةً"},{"id":"c","text":"عصفورًا"},{"id":"d","text":"أرنبًا"}]'::jsonb, 'b', 'السؤال بأداة «ماذا» يبحث عن الشيء. النصّ يقول «وجدت ليلى قطّةً صغيرةً»، فالجواب قطّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0fa18ba7-2ea6-5e41-b79e-57b5c0166b77', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'في النصّ نفسه، أين وجدت ليلى القطّة؟', '[{"id":"a","text":"في الحديقة"},{"id":"b","text":"في المدرسة"},{"id":"c","text":"في الشارع"},{"id":"d","text":"في الغابة"}]'::jsonb, 'c', 'السؤال بأداة «أين» يبحث عن المكان. النصّ يقول «في الشارع»، فهو المكان الصحيح.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
