  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98919198-00d4-50da-be8c-6e7384d6570d', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'في النصّ نفسه، ما الحدث الأخير؟', '[{"id":"a","text":"أطعمت القطّةَ"},{"id":"b","text":"وجدت القطّةَ"},{"id":"c","text":"ذهبت إلى السوق"},{"id":"d","text":"باعت القطّةَ"}]'::jsonb, 'a', 'نرتّب الأحداث: وجدت القطّة أوّلًا، ثمّ حملتها، وأخيرًا أطعمتها. فالحدث الأخير هو الإطعام.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
