  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('811ceb33-149f-56f3-b417-3c013cab6249', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'أيّ سؤالٍ نجيب عنه بكلمة «لأنّها كانت جائعة»؟', '[{"id":"a","text":"أين أطعمت ليلى القطّة؟"},{"id":"b","text":"مَن أطعم القطّة؟"},{"id":"c","text":"متى أطعمت القطّة؟"},{"id":"d","text":"لماذا أطعمت ليلى القطّة؟"}]'::jsonb, 'd', 'جوابٌ يبدأ بـ«لأنّ» هو سببٌ، والسبب نسأل عنه بأداة «لماذا». فالسؤال المناسب «لماذا أطعمت ليلى القطّة؟».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4717cb2e-73fb-51cc-b78c-1be8e05e701a', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'في النصّ السابق، ما معنى «حملتها»؟', '[{"id":"a","text":"رمَتها بعيدًا"},{"id":"b","text":"نظرت إليها"},{"id":"c","text":"أخذتها بيديها ورفعتها"},{"id":"d","text":"تركتها في الشارع"}]'::jsonb, 'c', 'نفهم المعنى من السياق: ليلى أحبّت القطّة وأخذتها إلى البيت، فـ«حملتها» تعني أخذتها بيديها ورفعتها.', 5)
