  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f17ddfc-0987-5a7e-8335-c434c43761d6', '88b1c3a8-e57f-570c-b67a-e92514896ba2', 'ما الفكرة العامّة لهذا النصّ؟', '[{"id":"a","text":"ليلى تعتني بقطّةٍ وجدتها وتطعمها"},{"id":"b","text":"ليلى تذهب إلى المدرسة"},{"id":"c","text":"ليلى تلعب بالكرة"},{"id":"d","text":"ليلى تساعد أمّها في الطبخ"}]'::jsonb, 'a', 'الفكرة العامّة تشمل النصّ كلّه: ليلى وجدت قطّةً واعتنت بها وأطعمتها. باقي الخيارات أحداثٌ غير موجودةٍ في النصّ.', 6)
