INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07bcc384-b71b-588d-978f-cb813ed3a063', '245b23da-0aff-5e52-8978-e38dfb202b7d', 'اقرأ النصّ: «في عطلة الصيف، سافرت العائلةُ إلى الريف. هناك شاهد كريمٌ الدجاجَ والأبقار. في المساء، جلسوا حول النار يسمعون حكايات الجدّة. عاد كريمٌ سعيدًا بما تعلّمه.»  إلى أين سافرت العائلة؟', '[{"id":"a","text":"إلى المدينة"},{"id":"b","text":"إلى البحر"},{"id":"c","text":"إلى الريف"},{"id":"d","text":"إلى الجبل"}]'::jsonb, 'c', 'السؤال بأداة «إلى أين» يبحث عن المكان. النصّ يقول «سافرت العائلةُ إلى الريف»، فالجواب الريف.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b321eaa-ad9c-520d-98ee-6f62fd400895', '245b23da-0aff-5e52-8978-e38dfb202b7d', 'في النصّ نفسه، ماذا شاهد كريمٌ في الريف؟', '[{"id":"a","text":"السيّارات والقطارات"},{"id":"b","text":"الدجاجَ والأبقار"},{"id":"c","text":"السمكَ والمراكب"},{"id":"d","text":"الطائراتِ والمطار"}]'::jsonb, 'b', 'السؤال بأداة «ماذا» يبحث عن الأشياء. النصّ يقول «شاهد كريمٌ الدجاجَ والأبقار»، فهما الجواب.', 2)
