  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc48fb7f-1c2f-5308-afe9-e9901b436299', '245b23da-0aff-5e52-8978-e38dfb202b7d', 'في النصّ نفسه، ماذا فعلت العائلة في المساء؟', '[{"id":"a","text":"لعبوا كرةَ القدم"},{"id":"b","text":"ساروا في السوق"},{"id":"c","text":"ناموا مبكّرين"},{"id":"d","text":"جلسوا حول النار يسمعون حكايات الجدّة"}]'::jsonb, 'd', 'السؤال عن الزمان والحدث معًا. النصّ يقول «في المساء، جلسوا حول النار يسمعون حكايات الجدّة»، فهذا هو الجواب.', 3)
