INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d14b2202-69c2-5160-9235-ad4654b407bc', '245b23da-0aff-5e52-8978-e38dfb202b7d', 'ما الذي جعل كريمًا يعود سعيدًا؟', '[{"id":"a","text":"لأنّه تعلّم أشياء جديدةً في الريف"},{"id":"b","text":"لأنّه اشترى لعبةً غالية"},{"id":"c","text":"لأنّه ربح في مسابقةٍ"},{"id":"d","text":"لأنّه نام كثيرًا"}]'::jsonb, 'a', 'النصّ يقول «عاد كريمٌ سعيدًا بما تعلّمه». السبب نسأل عنه بأداة «لماذا/ما الذي»، والجواب أنّه تعلّم أشياء جديدة. الخطأ الشائع اختيار سببٍ غير مذكورٍ في النصّ.', 4)
