INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ad56ed2-e425-594c-8f27-7a9b6a6a3e40', '245b23da-0aff-5e52-8978-e38dfb202b7d', 'رتّب الأحداث: «جلسوا حول النار» — «سافرت العائلة» — «عاد كريمٌ سعيدًا». ما الترتيب الصحيح؟', '[{"id":"a","text":"عاد سعيدًا، ثمّ سافرت، ثمّ جلسوا"},{"id":"b","text":"جلسوا، ثمّ سافرت، ثمّ عاد سعيدًا"},{"id":"c","text":"سافرت، ثمّ جلسوا، ثمّ عاد سعيدًا"},{"id":"d","text":"سافرت، ثمّ عاد سعيدًا، ثمّ جلسوا"}]'::jsonb, 'c', 'نتبع النصّ: أوّلًا سافرت العائلة، ثمّ في المساء جلسوا حول النار، وأخيرًا عاد كريمٌ سعيدًا. الخطأ الشائع جعلُ العودة قبل الجلوس.', 5)
