INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce2a2b46-7da5-500b-a7fc-68c0b64cb596', '187f472a-ee3a-5423-a77a-d66088ec82fe', 'اقرأ: «يستيقظ أحمدُ مبكّرًا، ويغسل وجهه، ثمّ يتناول فطوره، وأخيرًا يذهب إلى المدرسة.»  ما أوّل عملٍ يقوم به أحمد؟', '[{"id":"a","text":"يستيقظ مبكّرًا"},{"id":"b","text":"يذهب إلى المدرسة"},{"id":"c","text":"يتناول فطوره"},{"id":"d","text":"يغسل وجهه"}]'::jsonb, 'a', 'نرتّب بكلمات: ثمّ، وأخيرًا. النصّ يبدأ بـ«يستيقظ أحمدُ مبكّرًا»، فهو العمل الأوّل.', 1)
