INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4e437de-eb75-567f-bc62-04830158623f', '187f472a-ee3a-5423-a77a-d66088ec82fe', 'أيّ أداةٍ تناسب السؤال: «……… ذهب أحمدُ؟» إذا كان الجواب «إلى المدرسة»؟', '[{"id":"a","text":"متى"},{"id":"b","text":"أين"},{"id":"c","text":"مَن"},{"id":"d","text":"لماذا"}]'::jsonb, 'b', 'الجواب «إلى المدرسة» مكان، والمكان نسأل عنه بأداة «أين». فنقول: أين ذهب أحمد؟', 3)
