INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f791eb99-8ef9-5869-8cef-e720f25e3b59', '187f472a-ee3a-5423-a77a-d66088ec82fe', 'اقرأ: «فرحت سلمى لأنّها نجحت في الامتحان.»  لماذا فرحت سلمى؟', '[{"id":"a","text":"لأنّها سافرت"},{"id":"b","text":"لأنّها مرضت"},{"id":"c","text":"لأنّها لعبت"},{"id":"d","text":"لأنّها نجحت في الامتحان"}]'::jsonb, 'd', 'السبب نسأل عنه بأداة «لماذا»، والجواب في النصّ: «لأنّها نجحت في الامتحان». نعود إلى النصّ لنجد السبب.', 5)
