INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('426e202f-2b7f-5cc8-a66e-03ed81aa1268', '187f472a-ee3a-5423-a77a-d66088ec82fe', 'نصٌّ يصف كيف يساعد ماجدٌ أمَّه في ترتيب البيت كلَّ يومٍ. ما فكرته العامّة؟', '[{"id":"a","text":"ماجدٌ يكره المدرسة"},{"id":"b","text":"ماجدٌ يساعد أمَّه في ترتيب البيت"},{"id":"c","text":"ماجدٌ يلعب طوال اليوم"},{"id":"d","text":"ماجدٌ مسافرٌ بعيدًا"}]'::jsonb, 'b', 'الفكرة العامّة تشمل النصّ كلّه: مساعدة ماجدٍ أمَّه في ترتيب البيت. الخطأ الشائع اختيار فكرةٍ لا يذكرها النصّ.', 6)
