INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d35ab455-53ea-5f6d-8d78-d74625ca2d76', 'cee8c976-c187-5aa0-95cc-5faef562fc29', 'ما نوع الجملة: «العصفورُ جميلٌ»؟', '[{"id":"a","text":"جملة فعليّة"},{"id":"b","text":"جملة اسميّة"},{"id":"c","text":"ليست جملة"},{"id":"d","text":"سؤال"}]'::jsonb, 'b', 'الجملة بدأت بـ«العصفور» وهو اسم، والجملة التي تبدأ باسمٍ جملةٌ اسميّة.', 1)
