INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6694907-19e2-5412-8b71-d451c43a9285', 'cee8c976-c187-5aa0-95cc-5faef562fc29', 'في الجملة الاسميّة «القمرُ منيرٌ»، ما المبتدأ؟', '[{"id":"a","text":"منيرٌ"},{"id":"b","text":"في"},{"id":"c","text":"القمرُ"},{"id":"d","text":"لا يوجد مبتدأ"}]'::jsonb, 'c', 'المبتدأ هو الاسم الذي نبدأ به ونتحدّث عنه. بدأنا بـ«القمرُ»، فهو المبتدأ، و«منيرٌ» خبره.', 3)
