INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0399d382-24df-5108-9546-085ff9c0a141', 'cee8c976-c187-5aa0-95cc-5faef562fc29', 'في الجملة الفعليّة «شربَ الطفلُ الحليبَ»، مَن الفاعل (مَن قام بالعمل)؟', '[{"id":"a","text":"الحليبَ"},{"id":"b","text":"شربَ"},{"id":"c","text":"الطفلُ مع الحليب"},{"id":"d","text":"الطفلُ"}]'::jsonb, 'd', 'الفاعل هو الاسم الذي قام بالعمل. الذي شرب هو «الطفلُ»، فهو الفاعل، و«شربَ» فعلٌ و«الحليبَ» ما شُرب.', 4)
