INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eccb9973-366d-531e-82e9-7b0ae804e7dc', 'cee8c976-c187-5aa0-95cc-5faef562fc29', 'كيف نعرف بسرعةٍ أنّ الجملة اسميّةٌ أم فعليّة؟', '[{"id":"a","text":"نعدّ كلماتها"},{"id":"b","text":"ننظر إلى كلمتها الأولى: اسمٌ أم فعل"},{"id":"c","text":"ننظر إلى آخر كلمة"},{"id":"d","text":"نحسب حروفها"}]'::jsonb, 'b', 'القاعدة الذهبيّة: الكلمة الأولى تحدّد النوع؛ إن بدأت باسمٍ فهي اسميّة، وإن بدأت بفعلٍ فهي فعليّة.', 5)
