  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78942202-9a76-5464-b50a-112d1810df85', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'ما نوع الجملة: «الكتابُ مفيدٌ»؟', '[{"id":"a","text":"جملة فعليّة"},{"id":"b","text":"جملة اسميّة"},{"id":"c","text":"سؤال"},{"id":"d","text":"حرف"}]'::jsonb, 'b', 'بدأت بـ«الكتاب» وهو اسم، فالجملة اسميّة. الكلمة الأولى اسمٌ فالجملة اسميّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('228ba8f0-cb36-51ce-bf2f-03dd8e5d95ae', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'ما نوع الجملة: «رجعَ الأبُ مساءً»؟', '[{"id":"a","text":"جملة اسميّة"},{"id":"b","text":"كلمة واحدة"},{"id":"c","text":"جملة فعليّة"},{"id":"d","text":"عنوان"}]'::jsonb, 'c', 'بدأت بـ«رجع» وهو فعلٌ يدلّ على عمل، فالجملة فعليّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('764c50ed-8249-5a76-bd4e-84027da38815', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'أيُّ كلمةٍ تصلح لتبدأ بها جملةً اسميّة؟', '[{"id":"a","text":"المدرسةُ"},{"id":"b","text":"ذهبَ"},{"id":"c","text":"يأكلُ"},{"id":"d","text":"لعبتْ"}]'::jsonb, 'a', 'الجملة الاسميّة تبدأ باسم، و«المدرسةُ» اسم. أمّا ذهب ويأكل ولعبت فأفعال تبدأ بها جملةٌ فعليّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1797697a-add7-5d3e-9a91-d86d2974afa0', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'في الجملة «يلعبُ الأطفالُ الكرةَ»، مَن الفاعل؟', '[{"id":"a","text":"الكرةَ"},{"id":"b","text":"يلعبُ"},{"id":"c","text":"لا فاعل"},{"id":"d","text":"الأطفالُ"}]'::jsonb, 'd', 'الفاعل من قام بالعمل، والذين يلعبون هم «الأطفالُ»، فهم الفاعل، و«الكرةَ» هي ما يُلعب به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed933c00-ef87-5291-854e-94b3507c6b6f', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'حوّل الجملة الفعليّة «شربَ الولدُ» إلى جملةٍ اسميّة تبدأ بالاسم نفسه.', '[{"id":"a","text":"هل شربَ الولدُ؟"},{"id":"b","text":"الولدُ شربَ"},{"id":"c","text":"شربَ شربَ"},{"id":"d","text":"في الولدِ"}]'::jsonb, 'b', 'نجعل الاسم «الولدُ» أوّلًا فتصير «الولدُ شربَ» جملةً اسميّة (بدأت باسم). العبرة بمن يأتي أوّلًا في الجملة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df2e4a9e-e064-5e0e-84de-7be1edaa210c', '41a4063e-7d9f-5613-b8ef-9bfcff011660', 'أيُّ هذه الجمل جملةٌ فعليّة؟', '[{"id":"a","text":"السماءُ صافيةٌ"},{"id":"b","text":"الطعامُ لذيذٌ"},{"id":"c","text":"العصفورُ صغيرٌ"},{"id":"d","text":"غرّدَ العصفورُ"}]'::jsonb, 'd', '«غرّدَ العصفورُ» بدأت بفعلٍ (غرّد) فهي فعليّة. أمّا الباقي فبدأ بأسماء فهي اسميّة. الخطأ الشائع الخلط بين الجملتين بسبب تشابه الكلمات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', '94774826-0c1e-5d79-b8df-c6335d6088c4', 'arabic-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ بناء الجُمَل', 4, 300, 60, 'challenge', 'admin', 4)
