INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ca166e91-6ee5-5cf0-b6cf-953d16ce0ffa', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'ما نوع الجملة: «الجبلُ عالٍ»؟', '[{"id":"a","text":"جملة فعليّة"},{"id":"b","text":"سؤال"},{"id":"c","text":"جملة اسميّة"},{"id":"d","text":"كلمة واحدة"}]'::jsonb, 'c', 'بدأت بـ«الجبل» وهو اسم، فالجملة اسميّة. ننظر إلى الكلمة الأولى لتحديد النوع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a68b0086-ccfb-5d98-a240-55675c29b08e', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'اقرأ هاتين الجملتين: (1) «العاملُ يبني الجدارَ» (2) «يبني العاملُ الجدارَ». ما نوع كلٍّ منهما؟', '[{"id":"a","text":"كلتاهما فعليّة"},{"id":"b","text":"(1) اسميّة و(2) فعليّة"},{"id":"c","text":"كلتاهما اسميّة"},{"id":"d","text":"(1) فعليّة و(2) اسميّة"}]'::jsonb, 'b', 'الجملة (1) بدأت باسمٍ (العامل) فهي اسميّة، والجملة (2) بدأت بفعلٍ (يبني) فهي فعليّة. العبرة بالكلمة الأولى لا بالمعنى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25436f18-df2c-5802-b390-a2d24e9bf573', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'في الجملة «كسرَ الطفلُ الزجاجَ»، ما الفعل، ومن الفاعل، وما الذي وقع عليه الفعل؟', '[{"id":"a","text":"الفعل: الزجاجَ، الفاعل: كسرَ"},{"id":"b","text":"الفعل: الطفلُ، الفاعل: الزجاجَ"},{"id":"c","text":"الفعل: كسرَ، الفاعل: الطفلُ، والزجاجُ هو ما كُسر"},{"id":"d","text":"لا فعل في الجملة"}]'::jsonb, 'c', 'الفعل هو العمل (كسرَ)، والفاعل من قام به (الطفلُ)، و«الزجاجَ» هو ما وقع عليه الكسر. الخطأ الشائع جعل الاسم الأخير فاعلًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('900b5f77-35d2-5050-9676-0a6b9606e359', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'اختر العبارة الصحيحة عن الجملة الاسميّة والفعليّة.', '[{"id":"a","text":"الاسميّة تبدأ باسمٍ وأجزاؤها مبتدأ وخبر، والفعليّة تبدأ بفعلٍ وأجزاؤها فعل وفاعل"},{"id":"b","text":"كلتاهما تبدأ بفعل"},{"id":"c","text":"الاسميّة تبدأ بفعلٍ والفعليّة تبدأ باسم"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'الجملة الاسميّة تبدأ باسمٍ (مبتدأ + خبر)، والفعليّة تبدأ بفعلٍ (فعل + فاعل). الخطأ الشائع قلبُ التعريفين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a67b0c9-bdda-592e-a00b-682e7e9d62ce', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'أيُّ مجموعةٍ كلُّ جملها اسميّة؟', '[{"id":"a","text":"خرجَ الولدُ — البابُ مغلقٌ"},{"id":"b","text":"نامَ الطفلُ — أكلَ القطُّ"},{"id":"c","text":"جرى الحصانُ — طارَ الطائرُ"},{"id":"d","text":"الوردةُ جميلةٌ — الماءُ باردٌ"}]'::jsonb, 'd', '«الوردةُ جميلةٌ» و«الماءُ باردٌ» كلتاهما بدأتا باسمٍ فهما اسميّتان. باقي المجموعات تحوي جملًا فعليّة تبدأ بأفعال. الخطأ الشائع عدم فحص الكلمة الأولى لكلّ جملة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ff8955d-17f7-5eb2-bee2-856c0e1b0aa8', '50fa6e52-8cc7-58e2-a386-4bf7e3a6b14a', 'حوّل «يرسمُ خالدٌ» إلى جملةٍ اسميّة، و«المطرُ ينزلُ» إلى جملةٍ فعليّة. ما الصواب؟', '[{"id":"a","text":"خالدٌ يرسمُ / ينزلُ المطرُ"},{"id":"b","text":"يرسمُ يرسمُ / المطرُ المطرُ"},{"id":"c","text":"هل يرسمُ خالدٌ؟ / هل ينزلُ المطرُ؟"},{"id":"d","text":"في خالدٍ / في المطرِ"}]'::jsonb, 'a', 'للاسميّة نبدأ بالاسم: «خالدٌ يرسمُ»؛ وللفعليّة نبدأ بالفعل: «ينزلُ المطرُ». العبرة دائمًا بالكلمة الأولى. الخطأ الشائع تكرار الكلمة أو تحويلها إلى سؤال.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

