INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('781c80b5-9053-588c-afd2-562bb7e7fa2f', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'ما نوع الجملة: «العلمُ نورٌ»؟', '[{"id":"a","text":"جملة اسميّة"},{"id":"b","text":"جملة فعليّة"},{"id":"c","text":"سؤال"},{"id":"d","text":"حرف"}]'::jsonb, 'a', 'بدأت بـ«العلم» وهو اسم، فالجملة اسميّة. ننظر إلى الكلمة الأولى لنحكم على النوع.', 1)
