INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88a14907-aa84-500f-b7a5-93f90913504b', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'أيُّ هذه الكلمات نبدأ بها جملةً فعليّة؟', '[{"id":"a","text":"النهرُ"},{"id":"b","text":"الحقلُ"},{"id":"c","text":"البستانُ"},{"id":"d","text":"زرعَ"}]'::jsonb, 'd', 'الجملة الفعليّة تبدأ بفعل، و«زرعَ» فعلٌ يدلّ على عمل. أمّا النهر والحقل والبستان فأسماءُ أماكن تبدأ بها جملةٌ اسميّة.', 2)
