INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c2f888e-989f-53b8-ad5f-4a58b642965e', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'في الجملة الاسميّة «الفلّاحُ نشيطٌ»، ما المبتدأ؟', '[{"id":"a","text":"نشيطٌ"},{"id":"b","text":"الفلّاحُ"},{"id":"c","text":"في"},{"id":"d","text":"لا مبتدأ"}]'::jsonb, 'b', 'المبتدأ هو الاسم الذي نبدأ به ونتحدّث عنه (الفلّاحُ)، و«نشيطٌ» خبرٌ يُخبر عن حاله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55042df2-9a08-5f5d-a8d9-0797825c144f', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'في الجملة «حصدَ الفلّاحونَ القمحَ»، ما الفعل ومن الفاعل؟', '[{"id":"a","text":"الفعل: القمحَ، الفاعل: حصدَ"},{"id":"b","text":"الفعل: الفلّاحونَ، الفاعل: القمحَ"},{"id":"c","text":"الفعل: حصدَ، الفاعل: الفلّاحونَ"},{"id":"d","text":"لا فعل فيها"}]'::jsonb, 'c', 'الفعل هو العمل (حصدَ)، والفاعل من قام به (الفلّاحونَ)، و«القمحَ» هو ما حُصد. الخطأ الشائع جعل الاسم الأخير فاعلًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73a794eb-4e6c-5ba0-870f-ac5e626ab4ba', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'اختر الجملة الاسميّة الصحيحة التي تتكوّن من مبتدأ وخبر.', '[{"id":"a","text":"القمرُ منيرٌ"},{"id":"b","text":"أضاءَ القمرُ"},{"id":"c","text":"هل القمرُ؟"},{"id":"d","text":"في القمرِ"}]'::jsonb, 'a', '«القمرُ منيرٌ» جملةٌ اسميّة: «القمرُ» مبتدأ و«منيرٌ» خبر. أمّا «أضاءَ القمرُ» ففعليّة، والباقي ليس جملةً تامّة. الخطأ الشائع اختيار جملةٍ تبدأ بفعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f55f8e49-4153-5f0d-81c3-b1d1815ce166', 'c9453556-0c44-5a7d-8d84-6f889983bd0a', 'صنّف: «طلعتِ الشمسُ» و«الشمسُ مشرقةٌ». ما الصواب؟', '[{"id":"a","text":"«طلعتِ الشمسُ» اسميّة و«الشمسُ مشرقةٌ» فعليّة"},{"id":"b","text":"كلتاهما اسميّة"},{"id":"c","text":"كلتاهما فعليّة"},{"id":"d","text":"«طلعتِ الشمسُ» فعليّة و«الشمسُ مشرقةٌ» اسميّة"}]'::jsonb, 'd', '«طلعتِ الشمسُ» بدأت بفعلٍ (طلعت) فهي فعليّة، و«الشمسُ مشرقةٌ» بدأت باسمٍ (الشمس) فهي اسميّة. الخطأ الشائع الخلط بسبب وجود كلمة «الشمس» في الجملتين.', 6)
ON CONFLICT (id) DO UPDATE SET
