INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82064451-008a-5d99-891a-56a9df66935f', 'efbece3f-7fb6-5693-aec7-86ad537a0eb3', 'أيُّ هذه الكلمات جمعٌ يدلّ على أكثر من اثنين؟', '[{"id":"a","text":"أطفالٌ"},{"id":"b","text":"طفلان"},{"id":"c","text":"طفلٌ"},{"id":"d","text":"طفلة"}]'::jsonb, 'a', '«أطفالٌ» جمعٌ (جمع تكسير لـ«طفل») يدلّ على كثيرين. أمّا «طفلان» فمثنّى و«طفلٌ» و«طفلة» مفردان.', 3)
