INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5dae0da-cbe8-557d-96fb-aaaf84cfb338', 'efbece3f-7fb6-5693-aec7-86ad537a0eb3', 'ما جمع كلمة «مؤمنٌ» (جمع مذكّر سالم)؟', '[{"id":"a","text":"مؤمنان"},{"id":"b","text":"مؤمنة"},{"id":"c","text":"مؤمن"},{"id":"d","text":"مؤمنونَ"}]'::jsonb, 'd', 'جمع المذكّر السالم نكوّنه بزيادة «ون» (أو «ين»)، فيصير «مؤمنٌ» ← «مؤمنونَ». و«مؤمنان» مثنّى.', 4)
