INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9998eed6-0e3c-59d6-ae39-ad14cf085938', 'efbece3f-7fb6-5693-aec7-86ad537a0eb3', 'كلمة «بناتٌ» تنتهي بـ«ات» لكنّها جمع تكسير. لماذا؟', '[{"id":"a","text":"لأنّ مفردها «بنت» تغيّر شكلُه ولم نزد «ات» على كلمةٍ سالمة"},{"id":"b","text":"لأنّها مثنّى"},{"id":"c","text":"لأنّها تدلّ على واحدة"},{"id":"d","text":"لأنّها فعل"}]'::jsonb, 'a', 'مفرد «بنات» هو «بنت»، وتغيّر شكلُه في الجمع، فهو جمع تكسير محفوظ لا جمع مؤنّث سالم. الخطأ الشائع الحكم بالظاهر «ات» فقط.', 5)
ON CONFLICT (id) DO UPDATE SET
