  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afd3ac93-a219-50b6-bb30-cf009f6e83f4', 'efbece3f-7fb6-5693-aec7-86ad537a0eb3', 'صنّف بالترتيب: «عصفورٌ» — «عصافيرُ» — «عصفوران». ما الصواب؟', '[{"id":"a","text":"مفرد — مثنّى — جمع"},{"id":"b","text":"مفرد — جمع — مثنّى"},{"id":"c","text":"جمع — مفرد — مثنّى"},{"id":"d","text":"مثنّى — جمع — مفرد"}]'::jsonb, 'b', '«عصفورٌ» مفرد (1)، «عصافيرُ» جمع تكسير (كثيرون)، «عصفوران» مثنّى (2). فالترتيب: مفرد — جمع — مثنّى. الخطأ الشائع الخلط بين المثنّى والجمع.', 6)
ON CONFLICT (id) DO UPDATE SET
