  ('05157bf9-256c-5efe-afe4-41fcc5a52d3b', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'كلمة «نجمةٌ» ما نوعها؟', '[{"id":"a","text":"مفرد"},{"id":"b","text":"مثنّى"},{"id":"c","text":"جمع"},{"id":"d","text":"فعل"}]'::jsonb, 'a', '«نجمةٌ» تدلّ على واحدةٍ، والمفرد ما دلّ على واحدٍ فقط.', 1)
