INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65fac34a-029f-528a-ba0f-220674eae16f', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'حوّل المفرد «لاعبٌ» إلى مثنّى ثمّ إلى جمع مذكّر سالم. ما الصواب؟', '[{"id":"a","text":"المثنّى: لاعبون، الجمع: لاعبان"},{"id":"b","text":"المثنّى: لاعبات، الجمع: لاعب"},{"id":"c","text":"المثنّى: لاعبان، الجمع: لاعبونَ"},{"id":"d","text":"المثنّى: لاعب، الجمع: لاعبتان"}]'::jsonb, 'c', 'المثنّى بزيادة «ان» ← لاعبان (اثنان)، وجمع المذكّر السالم بزيادة «ون» ← لاعبونَ (كثيرون). الخطأ الشائع تبديل علامة المثنّى بعلامة الجمع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
