INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95e837f0-caf2-52ca-915e-e6f13add033b', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'أيُّ مجموعةٍ كلُّ كلماتها جمعٌ؟', '[{"id":"a","text":"كتابٌ — قلمٌ — بابٌ"},{"id":"b","text":"معلّمونَ — معلّماتٌ — كُتُبٌ"},{"id":"c","text":"ولدان — بنتان — بابان"},{"id":"d","text":"وردةٌ — شجرةٌ — نجمةٌ"}]'::jsonb, 'b', '«معلّمونَ» جمع مذكّر، «معلّماتٌ» جمع مؤنّث، «كُتُبٌ» جمع تكسير، فكلّها جموع. المجموعة (أ) و(د) مفردات، و(ج) مثنّيات. الخطأ الشائع عدم فحص علامة كلّ كلمة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
