INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf8395f2-7562-5e59-b74e-ae14c8a0c9b1', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'كلمة «أبوابٌ» مفردها «باب». ما نوع هذا الجمع، وكيف نعرفه؟', '[{"id":"a","text":"جمع مؤنّث سالم لأنّه ينتهي بـ«ات»"},{"id":"b","text":"مثنّى لأنّه يدلّ على اثنين"},{"id":"c","text":"مفرد لأنّه شيءٌ واحد"},{"id":"d","text":"جمع تكسير لأنّ شكل الكلمة تغيّر عن مفردها «باب»"}]'::jsonb, 'd', '«أبواب» تغيّر شكلُها عن المفرد «باب» ولم نزد «ون» ولا «ات»، فهي جمع تكسير محفوظ. الخطأ الشائع توقّع قاعدةٍ ثابتةٍ لجمع التكسير.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
