INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78bfab9f-dfcc-5960-86c5-0b3538d508a2', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'في الجملة «حضرتِ المعلّماتُ»، كم معلّمةً (تقريبًا) حضرت، وما نوع الكلمة؟', '[{"id":"a","text":"أكثر من اثنتين، والكلمة جمع مؤنّث سالم"},{"id":"b","text":"معلّمةٌ واحدة، والكلمة مفرد"},{"id":"c","text":"معلّمتان اثنتان، والكلمة مثنّى"},{"id":"d","text":"لا أحد، والكلمة فعل"}]'::jsonb, 'a', '«المعلّماتُ» جمع مؤنّث سالم (آخره «ات») فيدلّ على أكثر من اثنتين. الخطأ الشائع الخلط بين «معلّمتان» (مثنّى) و«معلّمات» (جمع).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4b2d8aa-aa77-575f-b5d5-5a2adca01da2', 'a8ae0cbe-2996-573c-a895-7178f3704163', 'اجمع هذه الكلمات صحيحًا: «بنتٌ» (مؤنّث سالم)، «مهندسٌ» (مذكّر سالم)، «قلمٌ» (تكسير). ما الصواب؟', '[{"id":"a","text":"بنتان — مهندسان — قلمان"},{"id":"b","text":"بناتٌ — مهندسونَ — أقلامٌ"},{"id":"c","text":"بناتٌ — مهندسات — أقلام"},{"id":"d","text":"بنت — مهندس — قلم"}]'::jsonb, 'b', '«بنت» مفردها مؤنّث لكنّ جمعها «بنات» محفوظ، «مهندس» ← مهندسونَ بزيادة «ون»، «قلم» ← أقلام جمع تكسير. الخيار (أ) مثنّيات، و(د) مفردات. الخطأ الشائع جمع المذكّر العاقل بـ«ات».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

