  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf925541-8e3a-5c68-a3ab-26ec010b6127', 'ce2a3f0c-e394-54aa-b00a-f84fe0ade359', 'حوّل «الطفلُ نظيفٌ» إلى المؤنّث. ما الصواب؟', '[{"id":"a","text":"الطفلُ نظيفةٌ"},{"id":"b","text":"الطفلةُ نظيفةٌ"},{"id":"c","text":"الطفلةُ نظيفٌ"},{"id":"d","text":"الأطفالُ نظافٌ"}]'::jsonb, 'b', 'نؤنّث الاسم وصفته معًا بزيادة التاء: الطفلةُ نظيفةٌ. الخطأ الشائع تأنيث كلمةٍ واحدةٍ وترك الأخرى مذكّرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
