  ('29b510ac-e84a-5ec0-b5f2-766cb9751c5f', '523d1d7b-bb04-5d44-939c-5426f74a3373', 'arabic-3eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ التذكير والتأنيث', 4, 300, 60, 'challenge', 'admin', 4)
