INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dca13e2a-9527-54b7-8435-f10b360e054f', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'أيُّ مجموعةٍ كلُّ كلماتها أسماءٌ مذكّرة؟', '[{"id":"a","text":"قلم، باب، أسد"},{"id":"b","text":"وردة، شمس، يد"},{"id":"c","text":"بنت، معلّمة، قطّة"},{"id":"d","text":"أرض، عين، نار"}]'::jsonb, 'a', 'قلم وباب وأسد كلُّها مذكّرٌ (نقول هذا) وبلا تاء. أمّا المجموعات الأخرى ففيها مؤنّثٌ بتاءٍ أو مؤنّثٌ بلا تاء مثل شمس ويد.', 1)
