  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('458d27be-cfe1-58ae-9553-2096b9a6d8b9', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'في جملة «دخلتِ التلميذةُ القسمَ وفتحتِ النافذةَ»، كم اسمًا مؤنّثًا؟', '[{"id":"a","text":"لا يوجد مؤنّث"},{"id":"b","text":"ثلاثة أسماء"},{"id":"c","text":"اسمان: التلميذة، النافذة"},{"id":"d","text":"اسمٌ واحدٌ: القسم"}]'::jsonb, 'c', '«التلميذة» و«النافذة» مؤنّثان بالتاء المربوطة. أمّا «القسم» فمذكّر. فالأسماء المؤنّثة اثنان.', 2)
ON CONFLICT (id) DO UPDATE SET
