  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85483e9b-77cb-59d8-99bc-bd4ca97607c4', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'ما مؤنّث كلمة «صديق»؟', '[{"id":"a","text":"أصدقاء"},{"id":"b","text":"صديقة"},{"id":"c","text":"صديق"},{"id":"d","text":"صداقة"}]'::jsonb, 'b', 'نحوّل المذكّر إلى مؤنّثٍ بزيادة التاء على الكلمة نفسها: صديق ← صديقة. أمّا «صداقة» فمعناها مختلف، و«أصدقاء» جمع.', 3)
