INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('132965a6-ebe5-5d64-9b51-2a097f754343', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'حوّل الجملة كاملةً إلى المؤنّث: «اللاعبُ الصغيرُ ماهرٌ». ما الصواب؟', '[{"id":"a","text":"اللاعبةُ الصغيرُ ماهرٌ"},{"id":"b","text":"اللاعبةُ الصغيرةُ ماهرٌ"},{"id":"c","text":"اللاعبُ الصغيرةُ ماهرةٌ"},{"id":"d","text":"اللاعبةُ الصغيرةُ ماهرةٌ"}]'::jsonb, 'd', 'نؤنّث الاسم وكلَّ صفاته بزيادة التاء: اللاعبةُ الصغيرةُ ماهرةٌ. الخطأ الشائع تأنيث بعض الكلمات وترك الباقي مذكّرًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c727ec0f-0110-5aa5-923b-155e099e8994', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'تلميذٌ قال: «كلمة (يد) مذكّرةٌ لأنّها بلا تاء». لماذا أخطأ؟', '[{"id":"a","text":"لأنّ (يد) فيها تاءٌ مربوطة خفيّة"},{"id":"b","text":"لأنّ كلَّ كلمةٍ قصيرةٍ مؤنّثة"},{"id":"c","text":"لأنّ (يد) من المؤنّث بلا تاء، نقول هذه يدٌ"},{"id":"d","text":"لأنّ (يد) جمعٌ وليست مفردًا"}]'::jsonb, 'c', 'الخطأ الشائع ظنُّ أنّ كلَّ اسمٍ بلا تاءٍ مذكّر. بل «يد» من المؤنّث المحفوظ بلا تاء، نقول «هذه يدٌ» مثل شمس وأمّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e49d185-894b-5f23-b8fd-761a1c94bd46', '29b510ac-e84a-5ec0-b5f2-766cb9751c5f', 'أيُّ جملةٍ كلُّ المطابقات فيها صحيحةٌ بين الأسماء وصفاتها؟', '[{"id":"a","text":"السماءُ صافٍ والشمسُ مشرقٌ"},{"id":"b","text":"الحديقةُ واسعٌ والوردةُ جميلٌ"},{"id":"c","text":"البابُ مفتوحةٌ والقلمُ جديدةٌ"},{"id":"d","text":"السماءُ صافيةٌ والشمسُ مشرقةٌ"}]'::jsonb, 'd', '«السماء» و«الشمس» مؤنّثتان بلا تاء، فتتبعهما صفةٌ مؤنّثة: صافيةٌ، مشرقةٌ. الخطأ الشائع وصفُهما بصفةٍ مذكّرة لأنّهما بلا تاء.', 6)
