INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27b99878-792a-5ba3-b292-8625c9280620', '3271104d-ada8-52e5-a99a-685170081abc', 'أيُّ مجموعةٍ كلُّ أفعالها في الزمن المضارع؟', '[{"id":"a","text":"كتبَ، لعبَ، شربَ"},{"id":"b","text":"اُكتبْ، اِلعبْ، اِشربْ"},{"id":"c","text":"كتابةٌ، لعبٌ، شربٌ"},{"id":"d","text":"يكتبُ، يلعبُ، يشربُ"}]'::jsonb, 'd', 'أفعال المضارع تبدأ بحرفٍ زائدٍ (ي): يكتبُ، يلعبُ، يشربُ. أمّا المجموعة الأولى فماضٍ، والثانية أمر، والثالثة أسماء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2dbce53-c167-53cc-b254-bb7b844b531e', '3271104d-ada8-52e5-a99a-685170081abc', 'حوّل الفعل «أكلَ» إلى الأمر. ما الصواب؟', '[{"id":"a","text":"كُلْ"},{"id":"b","text":"يأكلُ"},{"id":"c","text":"أكلَ"},{"id":"d","text":"أكلٌ"}]'::jsonb, 'a', 'أمر الفعل «أكلَ» هو «كُلْ»، وهو طلبٌ بأن يأكل. أمّا «يأكلُ» فمضارعٌ، و«أكلَ» ماضٍ، و«أكلٌ» اسم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a23424d-49c5-5bf4-8b09-9d903b551ab8', '3271104d-ada8-52e5-a99a-685170081abc', 'في جملة «………… الطيورُ في السماء أمسِ»، أيُّ فعلٍ يناسب الفراغ؟', '[{"id":"a","text":"تطيرُ"},{"id":"b","text":"طِرْ"},{"id":"c","text":"طارتْ"},{"id":"d","text":"طيرانٌ"}]'::jsonb, 'c', 'كلمة «أمسِ» تدلّ على الماضي، فيناسبها الفعل الماضي «طارتْ». الخطأ الشائع وضعُ المضارع «تطيرُ» مع «أمسِ» وهو تناقضٌ زمنيّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('611beec9-e0fb-5ef4-87e8-45363a6efb86', '3271104d-ada8-52e5-a99a-685170081abc', 'الفعل «كتبَ» في الأزمنة الثلاثة بالترتيب (ماضٍ ← مضارع ← أمر) هو:', '[{"id":"a","text":"يكتبُ ← كتبَ ← اُكتبْ"},{"id":"b","text":"كتبَ ← يكتبُ ← اُكتبْ"},{"id":"c","text":"اُكتبْ ← كتبَ ← يكتبُ"},{"id":"d","text":"كتبَ ← اُكتبْ ← يكتبُ"}]'::jsonb, 'b', 'الترتيب الصحيح: الماضي «كتبَ»، ثمّ المضارع «يكتبُ»، ثمّ الأمر «اُكتبْ». الخطأ الشائع تقديمُ المضارع أو الأمر على الماضي.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c28144cb-e093-55a9-bb06-5b19ae4aa213', '3271104d-ada8-52e5-a99a-685170081abc', 'أيُّ جملةٍ صحيحةٌ في مطابقة الفعل لكلمتها الدالّة على الزمن؟', '[{"id":"a","text":"يسافرُ غدًا إلى تونس"},{"id":"b","text":"سافرَ غدًا إلى تونس"},{"id":"c","text":"يسافرُ أمسِ إلى تونس"},{"id":"d","text":"اُكتبْ أمسِ الدرسَ"}]'::jsonb, 'a', '«غدًا» تدلّ على المستقبل فيناسبها المضارع: يسافرُ غدًا. الخطأ الشائع جمعُ الماضي مع «غدًا» أو المضارع مع «أمسِ»، وهو تناقضٌ زمنيّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de89c747-c8db-5ed2-b3ef-2ec9f6b55b50', '3271104d-ada8-52e5-a99a-685170081abc', 'تلميذٌ كتب: «اِلعبْ فعلٌ ماضٍ لأنّه عملٌ». ما تصحيحه؟', '[{"id":"a","text":"صحيحٌ، اِلعبْ فعلٌ ماضٍ"},{"id":"b","text":"اِلعبْ فعلُ أمرٍ يدلّ على طلبٍ، لا ماضٍ"},{"id":"c","text":"اِلعبْ فعلٌ مضارعٌ يدلّ على الآن"},{"id":"d","text":"اِلعبْ اسمٌ وليس فعلًا"}]'::jsonb, 'b', 'الخطأ الشائع الخلطُ بين الأمر والماضي. «اِلعبْ» فعلُ أمرٍ يدلّ على طلبٍ بأن يلعب، وليس ماضيًا انتهى ولا مضارعًا يحدث الآن.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

