INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5386d31-e4d0-52e6-980d-6af517378feb', '4c5ad3d4-3e1f-5b84-88b8-dedc518d71cb', 'في جملة «نظّفَ التلاميذُ القسمَ أمسِ»، ما زمن الفعل «نظّفَ»؟', '[{"id":"a","text":"الماضي"},{"id":"b","text":"المضارع"},{"id":"c","text":"الأمر"},{"id":"d","text":"اسمٌ"}]'::jsonb, 'a', '«نظّفَ» فعلٌ ماضٍ، وتؤكّده كلمة «أمسِ» الدالّة على الزمن الماضي. العمل وقع وانتهى.', 3)
