INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b01c6d6-b173-538f-aeb6-e043827f40ac', '5844d15b-59cc-5036-93c0-f09fe6f10455', 'ما الضميرُ المناسب لتعويض الاسم في الجملة: «محمّدٌ يلعبُ في الساحة» ← «……… يلعبُ في الساحة»؟', '[{"id":"a","text":"هي"},{"id":"b","text":"هو"},{"id":"c","text":"أنا"},{"id":"d","text":"أنتَ"}]'::jsonb, 'b', '«محمّد» اسمُ ولدٍ غائبٍ مفرد، فالضميرُ المناسب «هو» للمذكّر. نضع الضميرَ مكان الاسم.', 1)
