INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b01dcc3e-f51f-580f-963a-f5459a1b0698', 'd278bf4b-df35-5fa0-a9af-2058e0783d7e', 'أقولُ لصديقي محمّدٍ: «……… ولدٌ مهذّب». ما الضميرُ المناسب؟', '[{"id":"a","text":"هو"},{"id":"b","text":"أنتَ"},{"id":"c","text":"هي"},{"id":"d","text":"أنا"}]'::jsonb, 'b', 'أتحدّثُ إلى محمّدٍ مباشرةً وهو ولدٌ، فهو مخاطبٌ مذكّر، والضميرُ المناسب «أنتَ» بالفتحة.', 5)
