INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fc0f6fe-0684-58e0-91c9-7fa346852262', 'a3d27ced-4715-5176-8665-4d777d03bdab', 'اقرأ: «فاطمةُ تساعدُ أمَّها في البيت.»  ما الضميرُ الذي يعوّضُ «فاطمةُ»؟', '[{"id":"a","text":"هو"},{"id":"b","text":"أنتِ"},{"id":"c","text":"هي"},{"id":"d","text":"نحن"}]'::jsonb, 'c', '«فاطمة» اسمُ بنتٍ غائبةٍ مفردة، فالضميرُ المطابق «هي» للمؤنّث الغائب.', 1)
