INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a231fb56-c8ec-54ba-9c88-3ac5b7d87640', 'a3d27ced-4715-5176-8665-4d777d03bdab', 'أيُّ ضميرٍ من ضمائر المتكلّم؟', '[{"id":"a","text":"أنا"},{"id":"b","text":"هو"},{"id":"c","text":"أنتَ"},{"id":"d","text":"هي"}]'::jsonb, 'a', '«أنا» ضميرُ المتكلّم. أمّا «هو» و«هي» فللغائب، و«أنتَ» للمخاطب.', 2)
