INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74213fdc-2234-5d5d-ac5e-604c4bcc1cd3', 'a3d27ced-4715-5176-8665-4d777d03bdab', 'حوّل إلى ضميرٍ: «خالدٌ وسميرٌ ذهبا إلى الملعب» ← «……… ذهبا إلى الملعب».', '[{"id":"a","text":"هو"},{"id":"b","text":"هم"},{"id":"c","text":"هي"},{"id":"d","text":"أنا"}]'::jsonb, 'b', '«خالدٌ وسميرٌ» جماعةٌ غائبة، فالضميرُ المطابق «هم» للجمع المذكّر، لا «هو» المفرد.', 3)
