INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72eb0784-83c8-5c87-9053-6cf8a31b729a', 'a3d27ced-4715-5176-8665-4d777d03bdab', 'أقولُ لأختي سلمى: «……… بنتٌ ذكيّة». ما الضميرُ الصحيح؟', '[{"id":"a","text":"هي"},{"id":"b","text":"أنتَ"},{"id":"c","text":"هو"},{"id":"d","text":"أنتِ"}]'::jsonb, 'd', 'أتحدّثُ إلى سلمى مباشرةً وهي بنتٌ، فهي مخاطبةٌ مؤنّثة، والضميرُ المناسب «أنتِ» بالكسرة. الخطأ الشائع استعمالُ «هي» وهي للغائبة لا للمخاطبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
