INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8cdb1948-5e5b-51b8-b2c2-a8f1b331de8e', 'a3d27ced-4715-5176-8665-4d777d03bdab', 'في أيّ جملةٍ استُعمل الضميرُ استعمالًا صحيحًا مطابقًا للاسم؟', '[{"id":"a","text":"سعادُ: هو تلميذةٌ مجتهدة"},{"id":"b","text":"محمّدٌ: هي ولدٌ مهذّب"},{"id":"c","text":"ليلى: هي تلميذةٌ مجتهدة"},{"id":"d","text":"التلاميذُ: هو خرجوا"}]'::jsonb, 'c', 'المطابقة صحيحةٌ في «ليلى: هي»، لأنّ ليلى بنتٌ والضمير «هي» مؤنّث. الخطأ الشائع وضعُ «هو» لبنتٍ أو «هي» لولدٍ.', 5)
