INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d19cd344-51e6-51be-8d84-e82fb4fd8004', 'ba01b395-c901-5267-8409-3de6b96bb66f', 'حوّل: «اللاعبون فازوا بالمباراة» ← «……… فازوا بالمباراة».', '[{"id":"a","text":"هو"},{"id":"b","text":"هي"},{"id":"c","text":"أنا"},{"id":"d","text":"هم"}]'::jsonb, 'd', '«اللاعبون» جماعةٌ غائبة، فالضميرُ المطابق «هم» للجمع المذكّر، لا «هو» المفرد.', 3)
