  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf0eaf02-3697-5f34-8752-30f8a5b205dc', 'ba01b395-c901-5267-8409-3de6b96bb66f', 'في أيّ جملةٍ استُعمل الضميرُ خطأً (لا يطابقُ الاسم)؟', '[{"id":"a","text":"سعادُ: هو تلميذةٌ مجتهدة"},{"id":"b","text":"محمّدٌ: هو ولدٌ مهذّب"},{"id":"c","text":"ليلى: هي بنتٌ ذكيّة"},{"id":"d","text":"القطّةُ: هي صغيرةٌ"}]'::jsonb, 'a', '«سعاد» بنتٌ، فالصواب «هي» لا «هو». الخطأ الشائع وضعُ ضميرٍ مذكّرٍ لاسمٍ مؤنّث. باقي الجمل مطابقتُها صحيحة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c44fc90-dfb8-5376-88c0-3c3dbfaaaa99', 'ba01b395-c901-5267-8409-3de6b96bb66f', 'أتحدّثُ إلى صديقي عليٍّ مباشرةً وأقول: «……… بطلٌ في الرياضة». ما الضميرُ الصحيح؟', '[{"id":"a","text":"هو"},{"id":"b","text":"هي"},{"id":"c","text":"أنتَ"},{"id":"d","text":"أنا"}]'::jsonb, 'c', 'أتحدّثُ إلى عليٍّ مباشرةً وهو ولدٌ، فهو مخاطبٌ مذكّر، والضميرُ «أنتَ». الخطأ الشائع استعمالُ «هو» وهي للغائب لا للمخاطب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b5ad8ea-974f-54d2-83d6-bbb7a3c2ce0e', 'ba01b395-c901-5267-8409-3de6b96bb66f', 'أيُّ جملةٍ فيها ضميرُ متكلّمٍ يدلُّ على جماعة؟', '[{"id":"a","text":"نحن نحبُّ مدرستنا"},{"id":"b","text":"هو يقرأُ كتابًا"},{"id":"c","text":"أنتِ تلميذةٌ"},{"id":"d","text":"هي تكتبُ الدرس"}]'::jsonb, 'a', '«نحن» ضميرُ المتكلّم للجماعة. أمّا «هو» و«هي» فللغائب، و«أنتِ» للمخاطبة المفردة.', 6)
ON CONFLICT (id) DO UPDATE SET
