INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('697203c3-eeaf-5308-8158-c7a0a613df1b', '393beeec-d8e5-5eb7-8c21-bff568e38bae', 'الضميرُ «نحن» نستعملُه لـ:', '[{"id":"a","text":"بنتٍ واحدةٍ غائبة"},{"id":"b","text":"المتكلّم مع جماعته"},{"id":"c","text":"ولدٍ غائب"},{"id":"d","text":"بنتٍ نخاطبها"}]'::jsonb, 'b', '«نحن» ضميرُ المتكلّم للجماعة، أقولُه عن نفسي ومعي غيري مثل: نحن نلعبُ.', 1)
