INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc69ff00-9bed-559e-bb5f-1ca713c1fc65', '27bb1867-f5b0-5379-8022-a73f8bb3a3ee', 'أيُّ كلمةٍ تنتهي بتاءٍ مربوطة (ة)؟', '[{"id":"a","text":"بيت"},{"id":"b","text":"مدرسة"},{"id":"c","text":"نبات"},{"id":"d","text":"بنت"}]'::jsonb, 'b', '«مدرسة» نقفُ عليها فنسمعُ «هاء» (مدرسهْ)، فهي تاءٌ مربوطة. أمّا بيت ونبات وبنت فتُنطقُ تاءً عند الوقوف.', 1)
