INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c65d421-6a90-56d3-bea2-95dad610f727', '27bb1867-f5b0-5379-8022-a73f8bb3a3ee', 'في كلمة «الشّمس»، اللام:', '[{"id":"a","text":"تُكتبُ ولا تُنطق (شمسية)"},{"id":"b","text":"تُكتبُ وتُنطق (قمرية)"},{"id":"c","text":"لا تُكتبُ أصلًا"},{"id":"d","text":"تتحوّلُ إلى تنوين"}]'::jsonb, 'a', 'حرف الشين شمسيّ، فاللام في «الشّمس» تُكتبُ ولا تُنطق، ويُشدَّدُ ما بعدها (أشّْمس). فهي أل شمسية.', 3)
