INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b05ca4cc-fd2e-50c4-94fc-5d579e9e4c3b', '6353a8be-a2bb-5f17-87f1-777abbf22ddc', 'في جملة «رأيتُ ……… في السّماء»، أيُّ كتابةٍ للتنوين صحيحة؟', '[{"id":"a","text":"نجمن"},{"id":"b","text":"نجمًا"},{"id":"c","text":"نجمً"},{"id":"d","text":"نجمن ا"}]'::jsonb, 'b', 'المفعولُ به منوّنٌ بالفتح، ويُكتبُ بفتحتين وألفٍ: «نجمًا». ولا نكتبُ نونًا، فـ«نجمن» خطأ.', 3)
