INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa54a32e-d579-5827-9e54-6ae89d70dae3', '449b7c01-3d96-55a9-ba33-1bd0d67ac93b', 'للتمييز بين التاء المربوطة والمفتوحة، ماذا نفعل؟', '[{"id":"a","text":"نعدّ حروف الكلمة"},{"id":"b","text":"نقفُ على الكلمة ونستمعُ للآخر"},{"id":"c","text":"ننظرُ إلى أوّل الكلمة"},{"id":"d","text":"نضعُ تنوينًا"}]'::jsonb, 'b', 'القاعدة: نقفُ على الكلمة؛ إن سمعنا «هاء» فهي مربوطة (ة)، وإن بقيت «تاء» فهي مفتوحة (ت).', 1)
