INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1ace32e-5290-5883-9019-f82cfdc5bdb7', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'التاءُ التي ننطقُها «هاء» عند الوقوف هي:', '[{"id":"a","text":"التاء المفتوحة (ت)"},{"id":"b","text":"التاء المربوطة (ة)"},{"id":"c","text":"اللام الشمسية"},{"id":"d","text":"تنوين الفتح"}]'::jsonb, 'b', 'التاء المربوطة (ة) ننطقُها «هاء» عند الوقوف مثل: مدرسهْ. أمّا المفتوحة فتبقى «تاء».', 1)
