INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae68af82-c374-5e2d-b6c1-980692460cef', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'الحروفُ الشمسية تُدغمُ فيها اللام، ومنها:', '[{"id":"a","text":"ش، س، ر، ن"},{"id":"b","text":"ق، ب، ج، م"},{"id":"c","text":"ا، ح، ع، ك"},{"id":"d","text":"ف، ه، و، ي"}]'::jsonb, 'a', 'الشين والسين والراء والنون حروفٌ شمسية تُدغمُ فيها اللام. أمّا ق ب ج م وغيرها فحروفٌ قمرية تُنطقُ معها اللام.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0acdaeb4-a142-5b43-a661-666bc601fbde', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'كلمة «الزّهرة»: نوعُ أل، ونوعُ التاء في آخرها:', '[{"id":"a","text":"أل قمرية، وتاءٌ مفتوحة"},{"id":"b","text":"أل قمرية، وتاءٌ مربوطة"},{"id":"c","text":"أل شمسية، وتاءٌ مربوطة"},{"id":"d","text":"أل شمسية، وتاءٌ مفتوحة"}]'::jsonb, 'c', 'حرف الزاي شمسيّ فاللام تُدغم (أزّهرة)، و«الزّهرة» نقفُ عليها فنسمعُ «هاء» فتاؤها مربوطة. فالجواب: شمسية وتاءٌ مربوطة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f9cfb79-e5f6-57be-9003-667fe02bd4a7', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'أيُّ جملةٍ كُتب فيها التنوينُ صحيحًا في كلّ كلماتها؟', '[{"id":"a","text":"رأيتُ ولدن يلعبُ"},{"id":"b","text":"هذا بابن كبير"},{"id":"c","text":"في الحديقة وردةن"},{"id":"d","text":"قطفتُ وردةً حمراء"}]'::jsonb, 'd', '«وردةً حمراء» تنوينُها صحيح (فتحتان بلا ألفٍ على التاء المربوطة، وفتحتان على «حمراء»). باقي الجمل كتبت نونًا مكان التنوين وهو خطأ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('967eb2a6-4c8b-5841-867d-8146422d7b8f', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'في أيّ كلمةٍ كانت أل قمرية (اللام تُنطق)؟', '[{"id":"a","text":"الشّجرة"},{"id":"b","text":"التّاج"},{"id":"c","text":"الصّخرة"},{"id":"d","text":"الهواء"}]'::jsonb, 'd', 'حرف الهاء قمريّ، فاللام في «الهواء» تُنطقُ ساكنةً (ألْهواء). أمّا الشين والتاء والصاد فحروفٌ شمسية تُدغمُ فيها اللام. الخطأ الشائع الخلطُ بين الحروف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b58dc983-3ad7-54ae-9d35-2eb50849cbac', '5ba78cf2-ba73-55b6-8b6e-076fc974efed', 'أيُّ كلمةٍ كُتبت تاؤها خطأً؟ (الصواب تاءٌ مربوطة)', '[{"id":"a","text":"بنت"},{"id":"b","text":"وقت"},{"id":"c","text":"مدرست"},{"id":"d","text":"بيت"}]'::jsonb, 'c', '«مدرسة» نقفُ عليها فنسمعُ «هاء»، فالصواب تاءٌ مربوطة «مدرسة» لا «مدرست». باقي الكلمات تاؤها مفتوحةٌ صحيحة. الخطأ الشائع كتابةُ المربوطة مفتوحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

