INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5efb1371-cbb1-5089-b149-7472b4f83964', '3a73a7b8-a76f-5df1-9863-3ef97515ae02', 'ما مرادفُ كلمة «فرِح» (الكلمة التي بنفس المعنى)؟', '[{"id":"a","text":"حزِن"},{"id":"b","text":"سُرَّ"},{"id":"c","text":"تعِب"},{"id":"d","text":"نام"}]'::jsonb, 'b', 'المرادفُ كلمةٌ بنفس المعنى. «فرِح» معناها «سُرَّ». أمّا «حزِن» فهو الضدّ لا المرادف.', 1)
