INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f75b1ab3-9a23-51ff-b278-0873f5cccf7d', '3a73a7b8-a76f-5df1-9863-3ef97515ae02', 'في المجموعة: (وردة — شجرة — قلم — عشب)، ما الكلمةُ الدخيلة (الغريبة)؟', '[{"id":"a","text":"وردة"},{"id":"b","text":"شجرة"},{"id":"c","text":"عشب"},{"id":"d","text":"قلم"}]'::jsonb, 'd', 'الكلمةُ الدخيلة هي «قلم» لأنّها لا تنتمي إلى عالم النبات، أمّا وردة وشجرة وعشب فكلُّها نباتاتٌ من حقل الحديقة.', 4)
