  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b394046c-142e-5a97-8c52-133bc9b7ab9e', '0b0c01ee-76e6-5c26-a8bd-20da42c8fab0', 'أيُّ زوجٍ من الكلمات هما ضدّان (وليسا مترادفين)؟', '[{"id":"a","text":"كبير — ضخم"},{"id":"b","text":"جميل — حسن"},{"id":"c","text":"بيت — منزل"},{"id":"d","text":"غنيّ — فقير"}]'::jsonb, 'd', '«غنيّ وفقير» ضدّان لأنّ معناهما متعاكس. أمّا (كبير/ضخم) و(جميل/حسن) و(بيت/منزل) فمترادفاتٌ بنفس المعنى. الخطأ الشائع الخلطُ بين الضدّ والمرادف.', 5)
ON CONFLICT (id) DO UPDATE SET
