  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99fa999c-db15-5f2b-be61-30f190b261ee', '0b0c01ee-76e6-5c26-a8bd-20da42c8fab0', 'أيُّ كلمةٍ لا تنتمي إلى الحقل المعجميّ لـ «الحديقة»؟', '[{"id":"a","text":"زهرة"},{"id":"b","text":"فراشة"},{"id":"c","text":"حافلة"},{"id":"d","text":"عشب"}]'::jsonb, 'c', '«حافلة» وسيلةُ نقلٍ لا تنتمي للحديقة. أمّا زهرة وفراشة وعشب فكلُّها من حقل الحديقة. الخطأ الشائع إدخالُ كلمةٍ من حقلٍ آخر.', 6)
